<style>
.khb-section {
  position: relative;
  overflow: hidden;
  padding: 5rem 0 6rem;
}

.khb-section::before {
  content: "";
  position: absolute;
  top: -200px;
  right: -200px;
  width: 600px;
  height: 600px;
  background: radial-gradient(circle, rgba(167,139,250,.08) 0%, transparent 70%);
  pointer-events: none;
}

.khb-header {
  display: flex;
  flex-wrap: wrap;
  align-items: flex-end;
  justify-content: space-between;
  gap: 1rem;
  margin-bottom: 3.5rem;
}

.khb-header__left {
  display: flex;
  flex-direction: column;
  gap: 0.3rem;
}

/* Grid */
.khb-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 0;
}

@media (max-width: 640px) {
  .khb-grid {
    grid-template-columns: 1fr;
  }
}

/* Item */
.khb-item {
  padding: 2.25rem 2rem 2.5rem;
  border-bottom: 1px solid color-mix(in srgb, currentColor 8%, transparent);
  position: relative;
  transition: background 0.3s ease;
}

.khb-item:nth-child(odd) {
  border-right: 1px solid color-mix(in srgb, currentColor 8%, transparent);
}

@media (max-width: 640px) {
  .khb-item:nth-child(odd) {
    border-right: none;
  }
  .khb-item {
    padding: 2rem 0.25rem;
  }
}

/* Last row — no bottom border */
.khb-item:nth-last-child(-n+2):not(.khb-item:nth-child(odd):last-child) {
  border-bottom: none;
}
.khb-item:last-child {
  border-bottom: none;
}
@media (max-width: 640px) {
  .khb-item:nth-last-child(-n+2) {
    border-bottom: 1px solid color-mix(in srgb, currentColor 8%, transparent);
  }
  .khb-item:last-child {
    border-bottom: none;
  }
}

/* Hover bg */
.khb-item::after {
  content: "";
  position: absolute;
  inset: 0;
  background: color-mix(in srgb, var(--color-primary, #7c3aed) 4%, transparent);
  opacity: 0;
  transition: opacity 0.3s ease;
  pointer-events: none;
}
.khb-item:hover::after {
  opacity: 1;
}

/* Icon */
.khb-icon-wrap {
  width: 128px;
  height: 128px;
}

.khb-icon-wrap svg {
  width: 100%;
  height: 100%;
  display: block;
}

/* Title */
.khb-item__title {
  font-size: 1rem;
  font-weight: 700;
  color: var(--text-heading);
  margin: 0 0 0.6rem;
  line-height: 1.3;
  transition: color 0.2s;
}

.khb-item:hover .khb-item__title {
  color: var(--color-primary, #7c3aed);
}

/* Excerpt */
.khb-item__excerpt {
  font-size: 0.84rem;
  color: var(--text-muted);
  line-height: 1.7;
  margin: 0;
}
</style>

<?php if (!empty($_khb_items)): ?>
<section class="khb-section">
  <div class="container">

    <div class="khb-header">
      <div class="khb-header__left">
        <span class="text-eyebrow">Discover Bandung</span>
        <h2 class="text-sub-hero">Kenapa Harus Bandung?</h2>
      </div>
      <div>
        <p class="khb-lead">Bandung 2026: Perpaduan sempurna inovasi digital,<br>kesejukan alam, dan kreativitas kuliner terbaik.</p>
      </div>
    </div>

    <div class="khb-grid">
      <?php foreach ($_khb_items as $i => $_khb_item):
        $title   = htmlspecialchars($_khb_item['title'] ?? 'Untitled');
        $excerpt = htmlspecialchars($_khb_item['excerpt'] ?? '');
        $icon = $_khb_icons[$title] ?? '<svg viewBox="0 0 64 64" fill="none" xmlns="http://www.w3.org/2000/svg"><circle cx="32" cy="32" r="22" stroke="currentColor" stroke-width="2.2"/></svg>';
      ?>
      <div class="khb-item">
        <div class="khb-icon-wrap">
            <?= $icon ?>
        </div>
        <h3 class="khb-item__title"><?= $title ?></h3>
        <?php if ($excerpt): ?>
          <p class="khb-item__excerpt"><?= $excerpt ?></p>
        <?php endif; ?>
      </div>
      <?php endforeach; ?>
    </div>

  </div>
</section>
<?php endif; ?>
